sys_script_fix.script:
// Set this Variable to true to make all OU's permissive, 
// Leave this Variable false to set all OUs to unpermissive
var set_all_permissive = false;
var test = true;

update_OU_permissive();

function update_OU_permissive(){
	var permissiveSettingText = set_all_permissive?'Permissive':'non-Permissive';
	var countChangedOUs = 0;
	var countOUs = 0;
	var countOUsPermissive = 0;
	var countOUsNonPermissive = 0;
		var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy'); 
	grOU.query(); 
	while (grOU.next()) { 
		countOUs++;
		if(grOU.u_ou_is_permissive == true){
			countOUsPermissive++;
		} else {
			countOUsNonPermissive++;
		}
		if(grOU.u_ou_is_permissive != set_all_permissive){
			grOU.u_ou_is_permissive = set_all_permissive;
			grOU.setWorkflow(false); // do not trigger business rules/workflows
			grOU.autoSysFields(false); // do not update system fields
			// if test is true, then no updates made, but all of the OU's changed are counted and the log will report OUs that would change 
			if(!test){
				grOU.update('Fix Script - Tasker 2.7 - Change OU Permissive - for OU: ' + grOU.office_abbreviation + ' to ' + permissiveSettingText);
				gs.info('Fix Script - Tasker 2.7 - Changed OU Permissive - for OU: ' + grOU.office_abbreviation + ' to ' + permissiveSettingText);
			}
			countChangedOUs++;
		}
	}
	if(test){
		gs.info('Fix Script - Tasker 2.7 - Change OU Permissive - TEST RUN TO SHOW COUNTS - found (' + countOUs + ') OUs in System. ('+ countOUsNonPermissive + ') are permissive.  ('+ countOUsNonPermissive + ') are non-permissive.  - Change "test" variable to false in the Fix Script  to update ('+ countChangedOUs + ') to ' + permissiveSettingText);
	}else{
		gs.info('Fix Script - Tasker 2.7 - Change OU Permissive - found (' + countOUs + ') OUs in System. ('+ countOUsNonPermissive + ') were set to permissive before fix script run.  ('+ countOUsNonPermissive + ') were set to non-permissive before fix script run.  - Fix Script updated ('+ countChangedOUs + ') to ' + permissiveSettingText);
	}
}
